#include <stdio.h>

int main() {
    for (int i = 1; i <= 5; i++) {
        printf("গণনা: %d\n", i);
    }
    return 0;
}

int i = 0;
while (i < 3) {
    printf("while: %d\n", i);
    i++;
}

int j = 0;
do {
    printf("do-while: %d\n", j);
    j++;
} while (j < 3);

for (int i = 1; i <= 10; i++) {
    if (i == 5) break;     // লুপ সম্পূর্ণ বন্ধ
    if (i % 2 == 0) continue; // এই ইটারেশন স্কিপ
    printf("%d ", i);
}
// আউটপুট: 1 3
